#include<bits/stdc++.h>
using namespace std;
#define int long long

const int N = 1e3 + 5;
const int M = 5e5 + 5;

int n, m, s;

int dis[N], cnt[N];
bool vis[N];

struct Edge
{
    int v, w;
};
vector<Edge> e[N];


bool SPFA()
{
    queue<int> q;
    memset(dis, -0x3f, sizeof dis);
    dis[s] = 0, vis[s] = 1;
    q.push(s);
    while(!q.empty())
    {
        int u = q.front();
        q.pop();
        vis[u] = 0;
        for(auto [v, w] : e[u])
        {
            if(dis[v] < dis[u] + w)
            {
                dis[v] = dis[u] + w;
                cnt[v] = cnt[u] + 1;
                if(!vis[v]) q.push(v), vis[v] = 1;
                if(cnt[v] >= n + 1) return 1;
            }
        }
    }
    return 0;
}

signed main()
{
    cin.tie(0) -> sync_with_stdio(0);
    cin >> m;
    n = 1000;
    s = 0;
    for(int i = 1; i <= m; i++)
    {
        int u, v, w;
        cin >> u >> v >> w;
        e[u - 1].push_back({v, w});
    }
    for(int i = 0; i < n; i++)
    	e[i].push_back({i + 1, 0});
    for(int i = 1; i <= n; i++)
    	e[i].push_back({i - 1, -1});
    SPFA();
    cout << dis[n];

    return 0;
}
